head.b:skin:
/* =========================================
   ACBPT Certificate Verification Theme
   Palette: Navy / White / Red
   Font: Tajawal
========================================= */
@import url('https://fonts.googleapis.com/css2?family=Roboto:wght@400;500;700;900&display=swap');

:root {
  --navy: #161c37;
  --navy-soft: #1d2850;
  --white: #ffffff;
  --red: #c1121f;
  --red-soft: #df1f2c;
  --gray-100: #f4f6fb;
  --gray-200: #e9edf7;
  --gray-300: #d6deef;
  --gray-600: #4b556b;
  --shadow: 0 14px 34px rgba(22, 28, 55, 0.12);
  --radius: 14px;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

body {
  font-family: 'Roboto', Arial, sans-serif;
  background: linear-gradient(180deg, #f7f9ff 0%, var(--gray-100) 100%);
  color: var(--navy);
  line-height: 1.5;
}

a {
  color: inherit;
  text-decoration: none;
}

.app-shell {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.site-header {
  background: var(--white);
  border-top: 4px solid var(--red);
  border-bottom: 1px solid var(--gray-200);
  padding: 18px 16px 16px;
}

.header-section {
  margin: 0 auto;
  width: 100%;
}

.logo-wrap {
  display: flex;
  justify-content: center;
}

.logo-link {
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.site-logo {
  width: 130px;
  max-width: 100%;
  height: auto;
  border-radius: 12px;
}

.logo-text {
  font-size: 1.6rem;
  font-weight: 900;
  letter-spacing: 0.03em;
  color: var(--navy);
}

.site-main {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px 14px;
}

.card {
  width: 100%;
  max-width: 680px;
  background: var(--white);
  border: 1px solid var(--gray-300);
  border-top: 4px solid var(--red);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  padding: 26px 18px;
}

.verify-title {
  text-align: center;
  margin: 0 0 14px;
  font-size: 1.35rem;
  font-weight: 900;
  color: var(--navy);
}

.verify-subtitle {
  text-align: center;
  margin: -8px 0 20px;
  color: var(--gray-600);
  font-size: 0.95rem;
}

.search-form {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.search-input {
  width: 100%;
  border: 1px solid var(--gray-300);
  border-radius: 10px;
  background: #fbfcff;
  min-height: 48px;
  padding: 0 14px;
  font-size: 1rem;
  color: var(--navy);
  outline: none;
}

.search-input:focus {
  border-color: var(--navy);
  box-shadow: 0 0 0 3px rgba(11, 30, 79, 0.12);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  border: 0;
  border-radius: 10px;
  min-height: 48px;
  padding: 0 16px;
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  transition: 0.2s ease;
}

.btn-primary {
  background: linear-gradient(135deg, var(--navy) 0%, var(--navy-soft) 100%);
  color: var(--white);
}

.btn-primary:hover {
  background: var(--navy-soft);
}

.btn-back {
  background: linear-gradient(135deg, var(--red) 0%, var(--red-soft) 100%);
  color: var(--white);
  margin-top: 16px;
}

.btn-back:hover {
  background: #a20f1a;
}

.certificate-card {
  text-align: center;
}

.certificate-id {
  margin: 0 0 14px;
  font-size: 1.45rem;
  color: var(--navy);
  font-weight: 800;
  word-break: break-word;
}

.certificate-image {
  display: flex;
  justify-content: center;
}

.certificate-image img {
  max-width: 100%;
  width: auto;
  height: auto;
  border-radius: 10px;
  border: 1px solid var(--gray-300);
}

.no-results {
  text-align: center;
  color: var(--red);
  font-size: 1.05rem;
  font-weight: 700;
  margin: 8px 0 4px;
}

.site-footer {
  background: linear-gradient(135deg, var(--navy) 0%, #11172f 100%);
  color: var(--white);
  text-align: center;
  padding: 18px 14px 20px;
}

.footer-copy {
  margin: 0 0 12px;
  font-size: 0.92rem;
}

.footer-socials {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 10px;
}

.social-link {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.12);
  border: 1px solid rgba(255, 255, 255, 0.28);
  transition: 0.2s ease;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.social-link:hover {
  transform: translateY(-1px);
  background: rgba(255, 255, 255, 0.22);
}

.social-link svg {
  width: 19px;
  height: 19px;
  fill: var(--white);
}

@media (min-width: 768px) {
  .site-main {
    padding: 36px 20px;
  }

  .card {
    padding: 30px 28px;
  }

  .search-form {
    flex-direction: row;
  }

  .search-form .search-input {
    flex: 1;
  }

  .search-form .btn {
    min-width: 170px;
  }
}
